member.example:
Bind the GameObject active state using a serialized binder field — the target GameObject is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private GameObjectVisibleBinder _isVisible;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isVisible;
    }


Bind the GameObject active state by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private GameObject _panel;
        
        private GameObjectVisibleBinder IsVisible =>
            new(_panel);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isVisible;
    }
